import { type ReactNode } from 'react';
/**
 * Tooltip handler type
 * @public
 */
export type AnnotationsTooltipHandler = (hoveredMarkers: AnnotationsTooltipItem[], closeMarkers: AnnotationsTooltipItem[][]) => ReactNode;
/**
 * Annotations tooltip data item
 * @public
 */
export interface AnnotationsTooltipItem {
    /**
     * Arbitrary extra fields from the marker, forwarded from the source data or slot props
     */
    [key: string]: unknown;
    /**
     * Starting point of the marker
     */
    start: Date | number;
    /**
     * Ending point of the marker. If not set, the marker will represent a value instead of a range
     */
    end?: Date | number;
    /**
     * The marker background color
     */
    color: string;
    /**
     * The marker title
     */
    title?: string;
    /**
     * The marker description
     */
    description?: string;
    /**
     * The marker symbol
     */
    symbol?: ReactNode;
}
/**
 * Tooltip Component Props
 * @public
 */
export interface AnnotationsTooltipProps {
    /**
     * Defines whether tooltip show be hidden or not
     * @defaultValue false
     */
    hidden?: boolean;
    /** The ChoroplethLayer tooltip handler template */
    children?: AnnotationsTooltipHandler;
}
/**
 * Annotations tooltip config
 * @public
 */
export interface AnnotationsTooltipConfig {
    hidden?: boolean;
    /** Map from children to template prop internally */
    template?: AnnotationsTooltipHandler;
}
